html:
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead, footer, print_settings=None, print_heading_template=None) -%}
{%- endmacro -%}

{% set trans_date = frappe.utils.getdate(doc.transaction_date) %}

<style>
.dego-po-container {
    font-family: "Arial", sans-serif;
    color: #000;
    line-height: 1.4;
    padding: 10px;
    font-size: 13px;
}
.gold-top-bar {
    height: 4px;
    background-color: #f1a417; /* Gold/yellow color matching the top border */
    margin-bottom: 10px;
}
.company-header {
    margin-bottom: 15px;
}
.company-name {
    font-weight: bold;
    font-size: 16px;
    color: #000;
}
.company-detail {
    font-size: 12px;
    color: #333;
}
.supplier-info {
    margin-top: 15px;
    margin-bottom: 15px;
    font-size: 13px;
}
.document-title {
    text-align: center;
    font-size: 20px;
    font-weight: bold;
    margin-top: 15px;
    margin-bottom: 15px;
    letter-spacing: 1px;
}
.document-no {
    color: red;
    font-size: 13px;
    font-weight: bold;
    margin-top: 5px;
}
.po-items-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 20px;
    font-size: 11px;
}
.po-items-table th, .po-items-table td {
    border: 1px solid #000;
    padding: 6px 4px;
    vertical-align: middle;
}
.po-items-table th {
    background-color: #e2efda; /* Pastel green from Excel */
    font-weight: bold;
    text-align: center;
}
.po-items-table tr.total-row td {
    background-color: #f2f2f2;
}
.item-description {
    font-size: 10px;
    color: #555;
    font-style: italic;
}
.agreements-section {
    margin-top: 20px;
    font-size: 12px;
}
.agreement-title {
    font-weight: bold;
    font-style: italic;
    margin-bottom: 8px;
}
.agreement-item {
    margin-bottom: 6px;
}
.item-num {
    font-weight: bold;
}
.item-val {
    margin-left: 5px;
}
.sub-item {
    margin-left: 20px;
    margin-top: 3px;
}
.attached-info {
    margin-top: 12px;
}
.signature-section {
    margin-top: 30px;
    page-break-inside: avoid;
}
.signature-date {
    text-align: right;
    font-style: italic;
    margin-bottom: 10px;
    padding-right: 5%;
}
.signature-table {
    width: 100%;
    border-collapse: collapse;
}
.signature-table td {
    border: none !important;
}
</style>

<div class="dego-po-container">
    <!-- Top Gold Border Line -->
    <div class="gold-top-bar"></div>

    <!-- Company Info Header -->
    <div class="company-header">
        <div class="company-name">CÔNG TY TNHH DEGO HOLDING</div>
        <div class="company-detail">Địa chỉ: B19 đường dẫn cầu Cần Thơ, QL1A, Khu dân cư Trung tâm văn hóa Tây Đô, Phường Cái Răng, Thành phố Cần Thơ, Việt Nam.</div>
        <div class="company-detail">Mã số thuế: 1801722464</div>
    </div>

    <!-- Supplier Recipient -->
    <div class="supplier-info">
        <div><strong>Kính gửi:</strong> {{ doc.supplier_name | upper }}</div>
        <div><strong>Địa chỉ:</strong> {{ doc.address_display or "" }}</div>
    </div>

    <!-- Document Title -->
    <div class="document-title">
        ĐƠN ĐẶT HÀNG
        <div class="document-no">Số: {{ doc.name }}</div>
    </div>

    <!-- Items Table -->
    <table class="po-items-table">
        <thead>
            <tr>
                <th style="width: 3%; text-align: center;">STT</th>
                <th style="width: 8%; text-align: center;">Mã</th>
                <th style="width: 25%; text-align: left;">Tên hàng hóa</th>
                <th style="width: 15%; text-align: left;">Xuất xứ/ Thông số kỹ thuật/ chất liệu</th>
                <th style="width: 5%; text-align: center;">ĐVT</th>
                <th style="width: 6%; text-align: right;">Số lượng</th>
                <th style="width: 8%; text-align: right;">Đơn giá VNĐ (Chưa VAT)</th>
                <th style="width: 5%; text-align: center;">VAT</th>
                <th style="width: 8%; text-align: right;">Đơn giá VNĐ (Đã VAT)</th>
                <th style="width: 10%; text-align: right;">Thành tiền</th>
                <th style="width: 10%; text-align: left;">Kho nhận</th>
                <th style="width: 10%; text-align: left;">Tên trên hóa đơn</th>
                <th style="width: 7%; text-align: left;">Ghi chú</th>
            </tr>
        </thead>
        <tbody>
            {% for item in doc.items %}
                {% set tax_map = frappe.utils.parse_json(item.item_tax_rate or '{}') %}
                {% set tax_rate = 0 %}
                {% for account, rate in tax_map.items() %}
                    {% set tax_rate = rate %}
                {% endfor %}
                {% if tax_rate == 0 %}
                    {% for tax in doc.taxes %}
                        {% if tax.charge_type == "On Net Total" and tax.rate %}
                            {% set tax_rate = tax.rate %}
                        {% endif %}
                    {% endfor %}
                {% endif %}

                {% set rate_with_vat = item.rate * (1 + tax_rate / 100) %}
                {% set amount_with_vat = item.qty * item.rate * (1 + tax_rate / 100) %}

                <tr>
                    <td style="text-align: center;">{{ loop.index }}</td>
                    <td style="text-align: center;">{{ item.item_code }}</td>
                    <td style="text-align: left;">
                        {{ item.item_name }}
                        {% if item.description and item.description != item.item_name %}
                            <br><span class="item-description">{{ item.description }}</span>
                        {% endif %}
                    </td>
                    <td style="text-align: left;">{{ item.custom_item_specs or "" }}</td>
                    <td style="text-align: center;">{{ item.uom }}</td>
                    <td style="text-align: right;">{{ frappe.format(item.qty, item.meta.get_field('qty'), doc) }}</td>
                    <td style="text-align: right;">{{ frappe.format(item.rate, item.meta.get_field('rate'), doc) }}</td>
                    <td style="text-align: center;">
                        {% if tax_rate > 0 %}
                            {{ tax_rate | round | int }}%
                        {% else %}
                            0%
                        {% endif %}
                    </td>
                    <td style="text-align: right;">{{ frappe.format(rate_with_vat, item.meta.get_field('rate'), doc) }}</td>
                    <td style="text-align: right;">{{ frappe.format(amount_with_vat, item.meta.get_field('amount'), doc) }}</td>
                    <td style="text-align: left;">{{ item.warehouse | replace(' - DHC', '') }}</td>
                    <td style="text-align: left;">{{ item.custom_invoice_name or "" }}</td>
                    <td style="text-align: left;"></td>
                </tr>
            {% endfor %}
            <tr class="total-row">
                <td colspan="9" style="text-align: center; font-weight: bold; text-transform: uppercase;">TỔNG CỘNG</td>
                <td style="text-align: right; font-weight: bold;">{{ doc.get_formatted("grand_total") }}</td>
                <td colspan="3"></td>
            </tr>
        </tbody>
    </table>

    <!-- Agreements Section -->
    <div class="agreements-section">
        <div class="agreement-title">* Thoả thuận khác:</div>

        <div class="agreement-item">
            <span class="item-num">1. Thời gian thanh toán/ Số ngày công nợ:</span>
            <span class="item-val">{{ doc.payment_terms_template or "Công nợ 30 ngày" }}</span>
        </div>

        <div class="agreement-item">
            <span class="item-num">2. Thời gian nhận hóa đơn:</span>
            <span class="item-val">{{ doc.custom_invoice_receive_time or "Chậm nhất 24h kể từ khi nhận hàng" }}</span>
        </div>

        <div class="agreement-item">
            <span class="item-num">3. Thông tin nhận hàng:</span>
            <div class="sub-item">- Phương thức giao nhận: {{ doc.custom_delivery_method or "Đường bộ" }}</div>
            <div class="sub-item">- Nơi giao: {{ doc.custom_delivery_place or doc.supplier_name }}</div>
            <div class="sub-item">- Địa chỉ: {{ doc.shipping_address_display or doc.address_display or "" }}</div>
            <div class="sub-item">- Người liên hệ bên mua: {{ doc.custom_buyer_contact or "" }}</div>
        </div>

        <div class="agreement-item">
            <span class="item-num">4. Thông tin nhận hóa đơn:</span>
            <div class="sub-item">- Tên đơn vị: CÔNG TY TNHH DEGO HOLDING</div>
            <div class="sub-item">- Mã số thuế: 1801722464</div>
            <div class="sub-item">- Địa chỉ: B19 đường dẫn cầu Cần Thơ, QL1A, Khu dân cư Trung tâm văn hóa Tây Đô, Phường Cái Răng, Thành phố Cần Thơ, Việt Nam.</div>
            <div class="sub-item">- Mail nhận hóa đơn: {{ doc.custom_billing_email or "phongsanxuat.luutru@gmail.com" }}</div>
        </div>

        <div class="attached-info">
            <strong>Các thông tin, file, hình ảnh gửi kèm đơn hàng:</strong> {{ doc.custom_attached_info or "File" }}
        </div>
    </div>

    <!-- Signatures -->
    <div class="signature-section">
        <div class="signature-date">Cần Thơ, ngày {{ trans_date.day }} tháng {{ trans_date.month }} năm {{ trans_date.year }}</div>
        <table class="signature-table">
            <tr>
                <td style="width: 50%; text-align: center; font-weight: bold;">Trưởng bộ phận</td>
                <td style="width: 50%; text-align: center; font-weight: bold;">Người lập</td>
            </tr>
            <tr style="height: 80px;">
                <td></td>
                <td></td>
            </tr>
        </table>
    </div>
</div>
